request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?matchType ?idValue WHERE {
  VALUES ?idLiteral { "1dccc40d34ef40f9b36123e2fbca1a63" }

  {
    ?model a bboExt:Model ;
           tai:normalizedId ?idValue .
    BIND("normalizedId" AS ?matchType)
    FILTER(STR(?idValue) = ?idLiteral)
  }
  UNION
  {
    ?model a bboExt:Model ;
           tai:originalId ?idValue .
    BIND("originalId" AS ?matchType)
    FILTER(STR(?idValue) = ?idLiteral)
  }
  OPTIONAL { ?model bbo:name ?modelName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?prop ?propValue WHERE {
  VALUES ?frag { "1dccc40d34ef40f9b36123e2fbca1a63" }

  {
    ?model a bboExt:Model ;
           tai:normalizedId ?propValue .
    FILTER(CONTAINS(LCASE(STR(?propValue)), LCASE(STR(?frag))))
    BIND("normalizedId" AS ?prop)
  }
  UNION
  {
    ?model a bboExt:Model ;
           tai:originalId ?propValue .
    FILTER(CONTAINS(LCASE(STR(?propValue)), LCASE(STR(?frag))))
    BIND("originalId" AS ?prop)
  }
  UNION
  {
    ?model a bboExt:Model ;
           bbo:id ?propValue .
    FILTER(CONTAINS(LCASE(STR(?propValue)), LCASE(STR(?frag))))
    BIND("bbo:id" AS ?prop)
  }
  UNION
  {
    ?model a bboExt:Model .
    FILTER(CONTAINS(LCASE(STR(?model)), LCASE(STR(?frag))))
    BIND("modelIRI" AS ?prop)
    BIND(STR(?model) AS ?propValue)
  }

  OPTIONAL { ?model bbo:name ?modelName . }
}
LIMIT 25
